/**
 * FedRAMP Compliance Framework Library
 *
 * NIST 800-53 Rev 5 control families mapped to FedRAMP Moderate baseline.
 * Includes POA&M management, continuous monitoring, 3PAO integration,
 * and ATO package generation support.
 *
 * FedRAMP Moderate baseline: 325 controls across 20 control families.
 */

export interface FedRAMPControl {
  id: string;
  family: string;
  familyCode: string;
  title: string;
  description: string;
  baseline: "low" | "moderate" | "high";
  status: "implemented" | "partially_implemented" | "planned" | "not_implemented" | "not_applicable" | "inherited";
  implementationStatus: string;
  responsibleRole: string;
  priority: "P1" | "P2" | "P3";
  crossMappings: { framework: string; controlId: string }[];
  automationLevel: "full" | "partial" | "manual";
  testProcedure: string;
  expectedEvidence: string[];
  poamRequired: boolean;
}

export interface POAMEntry {
  id: string;
  controlId: string;
  weakness: string;
  severity: "critical" | "high" | "moderate" | "low";
  scheduledCompletionDate: number;
  milestones: { description: string; dueDate: number; status: "complete" | "in_progress" | "not_started" }[];
  responsiblePOC: string;
  resources: string;
  vendorDependency: boolean;
  deviationRationale?: string;
  status: "open" | "in_progress" | "completed" | "delayed" | "accepted_risk";
  riskRating: number; // 1-25 (likelihood x impact)
}

export interface ATOPackageStatus {
  systemName: string;
  systemId: string;
  impactLevel: "low" | "moderate" | "high";
  authorizationType: "initial" | "reauthorization" | "significant_change";
  status: "pre_assessment" | "assessment" | "authorization" | "continuous_monitoring";
  documents: ATODocument[];
  assessor3PAO: string | null;
  authorizedDate: number | null;
  expirationDate: number | null;
  continuousMonitoringFrequency: "monthly" | "quarterly" | "annually";
}

export interface ATODocument {
  id: string;
  name: string;
  type: "ssp" | "sap" | "sar" | "poam" | "cis_workbook" | "pia" | "e_auth" | "fips_validation" | "incident_response" | "contingency_plan" | "config_mgmt";
  status: "draft" | "in_review" | "approved" | "expired";
  version: string;
  lastUpdated: number;
  required: boolean;
}

