// ─── POA&M Entries ──────────────────────────────────────────────────────────

export function generateFedRAMPPOAM(): POAMEntry[] {
  const now = Date.now();
  const controls = FEDRAMP_CONTROLS.filter(c => c.poamRequired);
  return controls.map((c, i) => ({
    id: `POAM-${String(i + 1).padStart(3, "0")}`,
    controlId: c.id,
    weakness: `${c.title}: ${c.implementationStatus.split(";").pop()?.trim() || "Implementation incomplete"}`,
    severity: c.priority === "P1" ? "high" as const : c.priority === "P2" ? "moderate" as const : "low" as const,
    scheduledCompletionDate: now + (30 + i * 15) * 24 * 60 * 60 * 1000,
    milestones: [
      { description: "Draft remediation plan", dueDate: now + 7 * 24 * 60 * 60 * 1000, status: "complete" as const },
      { description: "Implement technical controls", dueDate: now + (15 + i * 10) * 24 * 60 * 60 * 1000, status: "in_progress" as const },
      { description: "Validate and document evidence", dueDate: now + (25 + i * 15) * 24 * 60 * 60 * 1000, status: "not_started" as const },
    ],
    responsiblePOC: c.responsibleRole,
    resources: "Security engineering team + external 3PAO assessor",
    vendorDependency: c.id.startsWith("SA") || c.id.startsWith("PE"),
    status: "in_progress" as const,
    riskRating: c.priority === "P1" ? 15 : c.priority === "P2" ? 10 : 5,
  }));
}

