// ─── FedRAMP Family Summary ─────────────────────────────────────────────────

export function getFedRAMPFamilySummary() {
  const families = new Map<string, { code: string; total: number; implemented: number; partial: number; planned: number; notImpl: number; inherited: number; na: number }>();
  for (const c of FEDRAMP_CONTROLS) {
    if (!families.has(c.family)) {
      families.set(c.family, { code: c.familyCode, total: 0, implemented: 0, partial: 0, planned: 0, notImpl: 0, inherited: 0, na: 0 });
    }
    const f = families.get(c.family)!;
    f.total++;
    if (c.status === "implemented") f.implemented++;
    else if (c.status === "partially_implemented") f.partial++;
    else if (c.status === "planned") f.planned++;
    else if (c.status === "not_implemented") f.notImpl++;
    else if (c.status === "inherited") f.inherited++;
    else if (c.status === "not_applicable") f.na++;
  }
  return Array.from(families.entries()).map(([name, data]) => ({ name, ...data }));
}
